INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('infant-baptism', 'ceb', 'sacraments', 'Bunyag sa Bata', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa bunyag sa bata?', '"Ang Sta. Iglesya nagtudlo nga ang sacramento sa bunyag mao ang una sa mga sacramento nga atong madawat busa mao kini ang ganghaan ngadto sa atong espirituhanong kinabuhi. Ang bunyag mopapas sa salang panulondon ug mopasaylo sa mga salang buhatnon ug mowagtang sa kastigo temporal busa ang nabunyagan usa na ka bag-ong binuhat ug wala nay nahibilin diha kaniya nga gikaligutgotan sa Dios. Pinaagi niining maong sacramento madawat nato ang kinabuhi sa Dios (grasya nga makasantos) ug mahiusa kita ngadto ni Cristo ug mahimo kitang sakop sa lawas nga mistiko ni Cristo nga mao ang Iglesya . Sa pagbunyag kanato atong nadawat ang tulo ka diosnong birtud sa pagtuo, paglaom ug paghigugma sa Dios ug ang mga gasa sa Espiritu Santo. Tungod kay ang mga gagmayng bata natawo man diha sa kahimtang sa salang panulondon busa kinahanglan usab nga sila padawaton sa bunyag. Matud ni San Augustine nga, “ang salang panulondon mitapot sa kalag sa bata hawa sa iyang kasayuran busa mahimo sab kini nga kuhaon pinaagi sa bunyag hawa sa iyang kasayuran.”\n\nAng mga bata apil sa plano sa Dios sa kaluwasan, “kay kabubut-on sa Dios nga ang tanang tawo maluwas ug mahibalo sa kamatuoran” (1 Tim. 2:4). Si Jesus miingon, “ang inyong Amahan nga atua sa langit dili buot nga may mawala bisag usa niining mga gagmayng bata” (Mat. 18:14). Si Jesus nagtudlo kanato sa usa sa mga kondisyon aron ang tawo makasulod sa langit, “Walay makakita sa gingharian sa Dios gawas kon siya matawo pag-usab” (Jn. 3:3). Ug sa unsa mang paagiha nga mahitabo kini? Si Jesus mipadayon sa pagtudlo, “Sultihan ko ikaw: walay makasulod sa gingharian sa Dios gawas kon matawo siya pinaagi sa tubig ug sa Espiritu” (Jn. 3:5). Gipasabot kanato ni Jesus nganong kinahanglan nga ang tawo matawo pag-usab pinaagi sa tubig ug sa Espiritu, “Ang gianak sa tawo, tawo usab; ug ang gianak sa Espiritu, espiritu usab” (Jn. 3:6). Ang bata nga gihimugso niining kalibotana gianak sa tawo busa tawo usab (Jn 16:21) ug kinahanglan pa siya nga matawo pag-usab pinaagi sa tubig ug sa Espiritu aron siya mahimong anak sa Dios. Ang tubig dinhi nagpasabot sa bunyag, “Walo lamang ka tawo ang misulod sa arka ug naluwas sa tubig nga naghulagway sa bunyag nga karon nagluwas kaninyo” (1 Ped. 3:20-21), “kita iyang giluwas, dili tungod sa bisan unsang maayo nga atong nabuhat, kondili tungod sa iyang kaluoy pinaagi sa paghugas nga gihimo sa Espiritu Santo aron kita makabaton ug bag-ong kinabuhi” (Tito 3:5). Ang bata bunyagan aron pagkuha sa salang panulondon nga mitapot diha kaniya, “Daotan ako sukad ako mahimugso; ug makasasala sukad ako ipanamkon” (Sal. 51:5) ug aron siya mahiusa kang Cristo, “Gibunyagan kamo aron mahiusa kang Cristo, ug busa nakaambit na kamo sa kinaiya ni Cristo” (Gal. 3:27).\nAng kasaysayan sa unang mga kristohanon nagtug-an kanato nga apil ang mga gagmayng bata sa bunyag. Si San Irenaeus, nga tinun-an ni Polycarpio, nga tinun-an ni San Juan Ebanghelista miingon: “Si Cristo mianhi aron pagluwas sa tanan pinaagi kaniya; ang tanan nga natawo pag-usab (nabunyagan) diha kaniya-masuso ug mga gagmayng bata, mga batan-on, ug ang mga tigulang.” Usa ka pastor nga protestante nga si Dr. John Theodore Mueller sa iyang libro “Why Baptize Children?” pahina 3-4 miingon, “Gikan sa unang mga adlaw sa mga santos nga mga apostoles ang Kristhohanong tradisyon nagpadayon hangtod karon sa walay hunong ug walay bugto: ang Iglesya nagbunyag sa mga batang masuso. Si Tertulliano natawo sa amihanang Africa sa mga tuig 150 mimatuod sa kamatuoran nga sa iyang panahon ang pagbunyag sa bata maoy pagbansay nga makaylapon kaayo.” Ang Lutheran Encyclopedia nagaingon usab, “Gikan sa apostolikanhong panahon hangtod sa pagtungha sa tinuhoang Anabaptist sa ikanapulog unom ka siglo, ang doktrina sa pagbunyag sa bata walay usa nga milalis.”"'::jsonb, '[{"objection":"Ang bata bisan kon walay bunyag malangit gihapon kay si Jesus miingon: “kay ang Gingharian sa Dios ila sa sama niining mga bataa” (Mar. 10:14). Busa dili kinahanglan nga bunyagan ang bata.","response":"Ang gipasabot ni Jesus nga “ang Gingharian sa Dios ila sa sama niining mga bataa” (Mar. 10:14) mao kadtong mga bata nga gipaduol kaniya ug iyang gipanalanginan (Mar. 10:16). Ang bunyag mao ang pagpaduol sa mga bata ngadto kang Jesus, “Gibunyagan kamo aron mahiusa kang Cristo, ug busa nakaambit kamo sa kinaiya ni Cristo” (Gal. 3:27)."},{"objection":"Si Jesus miingon “Isangyaw kining Maayong Balita… Ang motuo ug magpabunyag maluwas” (Mar. 16:15-16) busa sa dili pa bunyagan, walihan una ug patuohon. Ang mga gagmayng bata wala pay pagtuo ug dili pa makasabot sa wali busa dili angay nga bunyagan.","response":"Ang giingon nga walihan una dayon patuohon sa dili pa bunyagan referido kini sa mga dagko na nga nakabig (Mar. 16:15-16). Dili tinuod nga ang gagmayng mga bata walay pagtuo, “Ug mahitungod niining gagmayng mga bata nga nagtuo kanako” (Mat. 18:6). “Ang mga bata ug ang mga masuso gibansay mo sa paghalad ug hingpit nga pagdayeg kanimo” (Mat. 21:16)."},{"objection":"“Ang tagsatagsa kaninyo kinahanglan maghinulsol ug magpabunyag” (Buh. 2:38) busa sa dili pa bunyagan pahinulsolon una. Ang mga bata dili pa makahinulsol busa walay labot sa bunyag.","response":"Ang gipasabot nga pahinulsolon sa dili pa bunyagan (Buh. 2:38) mao ang mga dagko nga kinabig nga nakahimo na og “actual sins” kun salang buhatnon apan ang mga anak sa mga kristyanos apil usab sa bunyag, “Kay saad sa Dios alang man kaninyo ug sa inyong mga anak” (Buh. 2:39). Daghang okasyon nga ang tibuok panimalay nabunyagan: panimalay ni Lydia (Buh. 16:15), panimalay sa guwardiya (Buh. 16:33) ug ang tibuok panimalay ni Estefanas (1 Cor. 1:16). Ang tibuok banay naglakip sa mga masuso (Joel 2:16). Sa Daang Tugon ang Dios namunyag apil sa mga bata (1 Cor. 10:2, Exo. 12:37)."},{"objection":"Si Jesus dako na nga nagpabunyag (Mat. 3:13-16) ug siya mao ang atong panig-ingnan (1 Ped. 2:21). Busa dako ra gyod ang angay nga bunyagan.","response":"Ang bunyag nga gidawat ni Jesus kang Juan dili mao ang hingpit nga bunyag. Si Juan Bautista miingon, “Nagbunyag ako kaninyo pinaagi sa tubig, apan may moabot nga mas labaw pa kay kanako… Magbunyag siya kaninyo pinaagi sa Espiritu Santo ug sa kalayo” (Luc. 3:16). Dunay mga tawo nga nakadawat sa bunyag ni Juan apan gibunyagan pag-usab (Buh. 19:2-5) Ang giingon nga si Cristo panig-ingnan dili kay dako na siyang gibunyagan kondili diha sa iyang pagpailob (1 Ped. 2:23) ug sa iyang pagkamapaubsanon (Fil. 2:5-8)."},{"objection":"Ang sala mao ang paglapas sa balaod (1 Juan 3:4) ug ang mga bata wala pay nahimo bisan unsa nga kalapasan (Rom. 9:11) busa ang mga bata walay sala ug dili angay nga bunyagan.","response":"Ang naa sa mga dagko mao ang sala nga paglapas sa sugo (Rom. 1:24) apan dunay sala nga dili personal nga paglapas sa sugo kondili miresulta sa unang paglapas ni Adan nga mitakod ngadto sa tanang tawo-lakip sa mga bata, “Daotan ako sukad ako mahimugso; ug makasasala sukad ako ipanamkon” (Sal. 51:5). “Nakasulod sa kalibotan ang sala pinaagi sa usa ka tawo, ug ang sala nagdalag kamatayon. Busa mikaylap ang kamatayon ngadto sa tanang katawhan kay nakasala man ang tanang tawo” (Rom. 5:12)."},{"objection":"Dili tinuod nga ang bata dunay salang panulondon, “Ang anak dili mag-antos sa sala sa iyang amahan” (Eze. 18:20).","response":"Mahitungod sa personal nga kadautan sa sala, ang mismo nga amahan nga maoy naghimo maoy manubag (Eze. 18:20) apan ang “negative effect” kun kadaut nga resulta sa iyang sala motakod kini ngadto sa iyang mga anak, “Nakasala ang among katigulangan ug nangamatay sila; ug kami ang nag-antos sa silot sa ilang mga sala” (Lam. 5:7)."},{"objection":"Ang formula nga gamiton sa pagbunyag mao ang ngalan ni Jesus ug dili trinitarian, “Busa misugo siya nga bunyagan sila sa ngalan ni Jesu-Cristo” (Buh. 10:48).","response":"Ang bunyag sa ngalan ni Jesu-Cristo nagkahulogan og “pinaagi sa gahom ug mando ni Jesus” tungod kay ang ngalan nagpasabot man og gahom kun autoridad, “Ug si Pedro miingon, walay akoy salapi o bulawan, apan hatagan ko ikaw niining ania kanako: sa ngalan ni Jesu-Cristo nga Nazaretnon, lakaw” (Buh. 3:6). “Unsa bang gahoma ang anaa kaninyo, ug kinsa mang ngalan ang gigamit ninyo?” (Buh. 4:7). Gigamit usab kini aron pagpalahi sa bunyag ni Juan (Buh. 19:1-5) apan ang pulong nga gamiton kadtong gitudlo ni Jesus, “ug bunyagi sila sa ngalan sa Amahan, sa Anak ug sa Espiritu Santo” (Mat. 28:19)."},{"objection":"Ang paagi sa pagbunyag pagtusmaw kun “immersion” ra gayod, “Tungod niini, sa pagbunyag kanato gilubong kita uban kaniya…” (Rom. 6:4).","response":"Dili kay pagtusmaw ra gayod ang paagi sa pagbunyag. Gitagna nga ang pagbisibis og tubig makapasaylo sa sala (Eze. 36:25) ug ang bunyag mao ang paghinlo sa sala diha sa Bag-ong Tugon (Heb. 10:22). Gihisgotan usab nga ang pagbubo sa tubig ug sa Espiritu makahinlo sa atong mga kalapasan (Isa. 44:3). Si Saulo gibunyagan sulod sa balay diin walay sapa o dagat (Buh. 9:16-18).\n\nPagtulon-an. Kinahanglan nga ang mga ginikanan dili maglangan sa pagpabunyag sa ilang mga anak sa labing madaling panahon gikan sa pagkahimugso niini. Kinahanglan nga panalipdan ug amomahan sa mga dagko ang mga bata nga nabunyagan diha sa kristohanong pagtulon-an. Sa matag adlaw kinahanglan nga atong bag-ohon kanunay ang mga saad nga atong gihimo diha sa bunyag sa pagsalikway ni Satanas ug sa tanan niyang mga lansis. Pasalamatan nato ang Dios sa paghatag kanato diha sa bunyag sa mga birtud sa pagtuo, paglaom ug paghigugma kauban sa grasya ug sa tanang mga gasa sa Espiritu Santo."}]'::jsonb, '["1 Tim. 2:4","Mat. 18:14","Jn. 3:3","Jn. 3:5","Jn. 3:6","1 Ped. 3:20-21","Tito 3:5","Sal. 51:5","Gal. 3:27","Mar. 10:14","Mar. 16:15-16","Mat. 18:6","Mat. 21:16","Buh. 2:38","Buh. 2:39","Luc. 3:16","Rom. 5:12","Eze. 18:20","Lam. 5:7","Buh. 10:48","Buh. 3:6","Buh. 4:7","Mat. 28:19","Rom. 6:4"]'::jsonb, '["infant baptism"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.045Z')
